import os
import shutil
import logging
from datetime import datetime
import threading

import tensorflow as tf
from tensorflow import keras
from flask import Flask, request, jsonify, send_from_directory
from werkzeug.utils import secure_filename

# --- Configuration ---
UPLOAD_FOLDER = 'data/train'  # Directory to store uploaded training images
MODEL_DIR = 'model'           # Directory to store the trained model
MODEL_FILENAME = 'community_model.h5'
IMG_HEIGHT = 128              # Target image height for model input
IMG_WIDTH = 128               # Target image width for model input
BATCH_SIZE = 32
EPOCHS = 5                    # Number of training epochs (set low for demo, increase for real training)

# --- Setup Logging ---
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

# --- Flask App Initialization ---
app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024  # 16 MB file size limit

# Ensure necessary directories exist
os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)

# --- Global State for Model and Training ---
current_model = None
is_training = False
training_thread = None
training_status_message = "No training started yet."
last_trained_timestamp = None
class_names = []  # List of detected class labels, populated after data load/training

# --- Helper Functions ---
def allowed_file(filename):
    """Checks if the file extension is allowed."""
    return '.' in filename and \
           filename.rsplit('.', 1)[1].lower() in {'png', 'jpg', 'jpeg', 'gif'}

def get_class_names_from_directory(data_dir):
    """Infers class names from subdirectories within the data_dir."""
    if not os.path.exists(data_dir):
        return []
    return sorted([d for d in os.listdir(data_dir) if os.path.isdir(os.path.join(data_dir, d))])

def load_and_preprocess_data():
    """
    Loads images from the UPLOAD_FOLDER using tf.keras.utils.image_dataset_from_directory
    and applies basic preprocessing.
    """
    global class_names
    logging.info(f"Loading data from: {UPLOAD_FOLDER}")

    # Check if there are class subdirectories to load from
    if not os.listdir(UPLOAD_FOLDER) or not any(os.path.isdir(os.path.join(UPLOAD_FOLDER, d)) for d in os.listdir(UPLOAD_FOLDER)):
        logging.warning("No class subdirectories found in UPLOAD_FOLDER. Cannot load data.")
        return None, None, []

    try:
        train_ds = tf.keras.utils.image_dataset_from_directory(
            UPLOAD_FOLDER,
            labels='inferred',
            label_mode='int',
            image_size=(IMG_HEIGHT, IMG_WIDTH),
            interpolation='nearest',
            batch_size=BATCH_SIZE,
            shuffle=True
        )

        class_names = train_ds.class_names
        logging.info(f"Detected classes: {class_names}")

        # Normalize image pixel values to [0, 1]
        def preprocess(image, label):
            image = tf.cast(image / 255.0, tf.float32)
            return image, label

        train_ds = train_ds.map(preprocess).cache().prefetch(buffer_size=tf.data.AUTOTUNE)

        return train_ds, len(class_names), class_names
    except Exception as e:
        logging.error(f"Error loading and preprocessing data: {e}")
        return None, None, []

def build_model(num_classes):
    """
    Constructs a new CNN model for image classification.
    """
    logging.info(f"Building new model for {num_classes} classes.")
    model = keras.Sequential([
        # keras.layers.Rescaling(1./255, input_shape=(IMG_HEIGHT, IMG_WIDTH, 3)), # Not needed if preprocess handles normalization
        keras.layers.InputLayer(input_shape=(IMG_HEIGHT, IMG_WIDTH, 3)), # Define input shape explicitly
        keras.layers.Conv2D(32, (3, 3), activation='relu'),
        keras.layers.MaxPooling2D((2, 2)),
        keras.layers.Conv2D(64, (3, 3), activation='relu'),
        keras.layers.MaxPooling2D((2, 2)),
        keras.layers.Conv2D(128, (3, 3), activation='relu'),
        keras.layers.MaxPooling2D((2, 2)),
        keras.layers.Flatten(),
        keras.layers.Dense(128, activation='relu'),
        keras.layers.Dense(num_classes) # Output layer with 'num_classes' units
    ])

    model.compile(
        optimizer='adam',
        loss=tf.keras.losses.SparseCategoricalCrossentropy(from_logits=True), # Use from_logits=True if no softmax activation on last layer
        metrics=['accuracy']
    )
    return model

def load_model_from_disk():
    """Loads a previously saved model from disk."""
    model_path = os.path.join(MODEL_DIR, MODEL_FILENAME)
    if os.path.exists(model_path):
        try:
            logging.info(f"Loading existing model from {model_path}")
            return keras.models.load_model(model_path)
        except Exception as e:
            logging.error(f"Error loading model: {e}. Model might be corrupted or incompatible.")
            return None
    logging.info("No existing model found on disk.")
    return None

def save_model_to_disk(model):
    """Saves the current model to disk."""
    model_path = os.path.join(MODEL_DIR, MODEL_FILENAME)
    logging.info(f"Saving model to {model_path}")
    model.save(model_path)

def train_model_async():
    """
    Asynchronous function to perform model training.
    Updates global state variables for status tracking.
    """
    global current_model, is_training, training_status_message, last_trained_timestamp, class_names

    is_training = True
    training_status_message = "Training started..."
    logging.info("Training process initiated.")

    try:
        train_ds, num_classes, detected_class_names = load_and_preprocess_data()

        if train_ds is None or num_classes < 2:
            training_status_message = "Training failed: Not enough data or classes (need at least 2 distinct classes)."
            logging.error(training_status_message)
            return

        # Update global class_names after successful data loading
        class_names = detected_class_names

        # Check if the existing model is compatible with the new number of classes.
        # If not, or if no model exists, build a new one.
        if current_model and current_model.layers[-1].units == num_classes:
            logging.info("Existing model is compatible with current number of classes. Continuing training (fine-tuning).")
        else:
            logging.info("Building a new model as existing one is incompatible or not found.")
            current_model = build_model(num_classes)

        # Perform training
        current_model.fit(train_ds, epochs=EPOCHS)

        save_model_to_disk(current_model)
        last_trained_timestamp = datetime.now().isoformat()
        
        total_images = sum([len(files) for r, d, files in os.walk(UPLOAD_FOLDER) if files])
        training_status_message = f"Training completed successfully with {total_images} images across {num_classes} classes."
        logging.info(training_status_message)

    except Exception as e:
        training_status_message = f"Training failed: {str(e)}"
        logging.error(f"Training error: {e}", exc_info=True)
    finally:
        is_training = False
        logging.info("Training process finished.")

# --- API Endpoints ---

@app.route('/')
def index():
    """Provides a basic welcome message and API endpoint overview."""
    return jsonify({
        "message": "Welcome to the Community AI Training API!",
        "endpoints": {
            "/status": "GET - Get current model and training status.",
            "/upload": "POST - Upload an image with its 'label' (form data).",
            "/train": "POST - Trigger model retraining.",
            "/predict": "POST - Make a prediction using the current model (requires image file)."
        }
    })

@app.route('/status', methods=['GET'])
def get_status():
    """Returns the current status of the model and training process."""
    global current_model, is_training, training_status_message, last_trained_timestamp, class_names
    
    num_classes_in_model = current_model.layers[-1].units if current_model else 0
    num_classes_in_data = len(get_class_names_from_directory(UPLOAD_FOLDER))

    return jsonify({
        "training_in_progress": is_training,
        "training_status": training_status_message,
        "model_loaded": current_model is not None,
        "last_trained": last_trained_timestamp,
        "num_classes_in_data": num_classes_in_data,
        "num_classes_in_model": num_classes_in_model,
        "current_class_names": class_names
    })

@app.route('/upload', methods=['POST'])
def upload_file():
    """
    Endpoint for users to upload training images.
    Expects a file under the 'file' key and a 'label' in form data.
    """
    if 'file' not in request.files:
        return jsonify({"error": "No file part"}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400
    
    label = request.form.get('label')
    if not label:
        return jsonify({"error": "Label is required in form data"}), 400
    
    if file and allowed_file(file.filename):
        # Sanitize label to be safe for directory names
        safe_label = secure_filename(label).lower()
        if not safe_label:
            return jsonify({"error": "Invalid label after sanitization"}), 400

        label_dir = os.path.join(app.config['UPLOAD_FOLDER'], safe_label)
        os.makedirs(label_dir, exist_ok=True)

        filename = secure_filename(file.filename)
        filepath = os.path.join(label_dir, filename)
        
        # Ensure unique filename to prevent overwriting existing files
        counter = 1
        original_filename_no_ext, ext = os.path.splitext(filename)
        while os.path.exists(filepath):
            filename = f"{original_filename_no_ext}_{counter}{ext}"
            filepath = os.path.join(label_dir, filename)
            counter += 1

        file.save(filepath)
        logging.info(f"Uploaded {filepath} for label '{safe_label}'")
        
        return jsonify({
            "message": "File uploaded successfully",
            "filename": filename,
            "label": safe_label,
            "path": filepath
        }), 201
    else:
        return jsonify({"error": "Allowed file types are png, jpg, jpeg, gif"}), 400

@app.route('/train', methods=['POST'])
def trigger_training():
    """
    Endpoint to trigger the model training process.
    Training runs in a separate thread to avoid blocking the API.
    """
    global is_training, training_thread
    if is_training:
        return jsonify({"message": "Training is already in progress. Please wait."}), 200
    
    # Ensure there's enough data (at least two classes) to perform meaningful classification
    data_classes = get_class_names_from_directory(UPLOAD_FOLDER)
    if len(data_classes) < 2:
        return jsonify({"error": "Need at least two distinct classes of data to start training. Please upload more data."}), 400
    
    training_thread = threading.Thread(target=train_model_async)
    training_thread.start()
    return jsonify({"message": "Training initiated in the background."}), 202

@app.route('/predict', methods=['POST'])
def predict():
    """
    Endpoint to make predictions using the current model.
    Expects an image file under the 'file' key.
    """
    global current_model, class_names

    if current_model is None:
        return jsonify({"error": "Model not trained yet or failed to load. Please train the model first."}), 400
    
    if 'file' not in request.files:
        return jsonify({"error": "No file part"}), 400
    file = request.files['file']
    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400
    
    if not allowed_file(file.filename):
        return jsonify({"error": "Allowed file types for prediction are png, jpg, jpeg, gif"}), 400

    try:
        # Load and preprocess the uploaded image for prediction
        img = tf.image.decode_image(file.read(), channels=3) # Decode to 3 channels (RGB)
        img = tf.image.resize(img, [IMG_HEIGHT, IMG_WIDTH]) # Resize to model input dimensions
        img = tf.expand_dims(img, axis=0) # Add batch dimension (model expects batch of images)
        img = tf.cast(img / 255.0, tf.float32) # Normalize pixel values

        # Make prediction
        predictions = current_model.predict(img)
        
        # Apply softmax to get probabilities since the last layer typically has no activation
        score = tf.nn.softmax(predictions[0])
        
        predicted_class_idx = tf.argmax(score).numpy()
        
        # Ensure class_names is populated to map index to name
        if not class_names:
            # Attempt to infer class names if not already set (e.g., if server restarted)
            temp_class_names = get_class_names_from_directory(UPLOAD_FOLDER)
            if temp_class_names:
                class_names = temp_class_names
            else:
                return jsonify({"error": "Class names not loaded. Please train the model first."}), 500

        predicted_class_name = class_names[predicted_class_idx]
        
        return jsonify({
            "prediction": predicted_class_name,
            "confidence": float(score[predicted_class_idx]),
            "all_class_confidences": {name: float(s) for name, s in zip(class_names, score)}
        })

    except Exception as e:
        logging.error(f"Prediction error: {e}", exc_info=True)
        return jsonify({"error": f"Failed to make prediction: {str(e)}"}), 500

# --- Initial Model Load on App Startup ---
# This block runs when the Flask app starts. It attempts to load a pre-existing model
# and infer class names from the data directory.
with app.app_context():
    logging.info("Attempting to load model on app startup...")
    current_model = load_model_from_disk()
    
    # Attempt to infer class names from the UPLOAD_FOLDER structure
    inferred_class_names = get_class_names_from_directory(UPLOAD_FOLDER)
    if inferred_class_names:
        class_names = inferred_class_names
        logging.info(f"Detected {len(class_names)} classes from data directory: {class_names}")
    else:
        logging.info("No class directories found in UPLOAD_FOLDER on startup.")

    if current_model and class_names:
        # Validate if the loaded model's output layer matches the inferred number of classes
        if current_model.layers[-1].units != len(class_names):
            logging.warning(
                f"Loaded model's output layer ({current_model.layers[-1].units} units) "
                f"does not match detected data classes ({len(class_names)}). "
                f"The model might be incompatible; it will be rebuilt on the next training."
            )
            current_model = None # Force a rebuild on next train if incompatible
        else:
            logging.info("Model loaded successfully and is compatible with detected data classes.")
    elif current_model:
        logging.warning("Model loaded but no data directories found to infer class names. "
                        "Prediction might not have correct labels without training first.")
    else:
        logging.info("No model found or loaded successfully on startup.")

